import{_ as e,o as r,c as t,ak as l}from"./chunks/framework.aEAtsvX-.js";const p=JSON.parse('{"title":"快速指南 - 0. 安装和开始","description":"","frontmatter":{},"headers":[],"relativePath":"quick_guides/0_install_and_start.md","filePath":"quick_guides/0_install_and_start.md"}'),i={name:"quick_guides/0_install_and_start.md"};function n(s,a,_,o,d,h){return r(),t("div",null,[...a[0]||(a[0]=[l('<h1 id="快速指南-0-安装和开始" tabindex="-1">快速指南 - 0. 安装和开始 <a class="header-anchor" href="#快速指南-0-安装和开始" aria-label="Permalink to “快速指南 - 0. 安装和开始”">​</a></h1><p><strong>加入qq群 276051457</strong></p><h2 id="_1-下载和安装启动器" tabindex="-1">1. 下载和安装启动器 <a class="header-anchor" href="#_1-下载和安装启动器" aria-label="Permalink to “1. 下载和安装启动器”">​</a></h2><p><strong>推荐使用<a href="https://ifdian.net/p/0164034c016c11ebafcb52540025c377" target="_blank" rel="noreferrer">PCL启动器</a></strong></p><ul><li>如果不能打开，请下载并安装<a href="https://ltcat.lanzouv.com/i1mhD2drlvpa" target="_blank" rel="noreferrer">运行环境</a></li></ul><p>更多有关PCL的错误，可以在群里<a href="/panda_server_guide_v2/asking_requirements.html">问群友</a>或者查看<a href="https://shimo.im/docs/qKPttVvXKqPD8YDC" target="_blank" rel="noreferrer">PCL常见问题</a></p><h2 id="_2-下载整合包-原版游戏" tabindex="-1">2. 下载整合包/原版游戏 <a class="header-anchor" href="#_2-下载整合包-原版游戏" aria-label="Permalink to “2. 下载整合包/原版游戏”">​</a></h2><p><strong>本服是插件服，不需要玩家安装任何模组，但是可以安装一些能改良原版游戏体验的模组。</strong></p><ul><li>推荐使用<a href="https://github.com/Redersha/Minecraft-JE-Panda-Server-Cilent-Modpack" target="_blank" rel="noreferrer">已经配置好的整合包</a>。</li><li>或者去PCL启动器的下载页面下载一个性能优化整合包</li></ul><h2 id="_3-将本服添加到服务器列表并开始游戏" tabindex="-1">3. 将本服添加到服务器列表并开始游戏 <a class="header-anchor" href="#_3-将本服添加到服务器列表并开始游戏" aria-label="Permalink to “3. 将本服添加到服务器列表并开始游戏”">​</a></h2><ol><li>启动游戏</li><li>点击‘多人游戏’</li><li>点击‘添加服务器’</li><li>填入服务器ip（需要你先加入qq群以获得ip）</li></ol><h2 id="_4-为账号设置登录密码" tabindex="-1">4. 为账号设置登录密码 <a class="header-anchor" href="#_4-为账号设置登录密码" aria-label="Permalink to “4. 为账号设置登录密码”">​</a></h2><ol><li>进入服务器</li><li>输入<code>/reg &lt;你的密码&gt; &lt;你的密码&gt;</code>并回车</li></ol><p><strong>服务器用玩家ID来存储玩家信息</strong></p><h2 id="_5-开始自由探索" tabindex="-1">5. 开始自由探索！ <a class="header-anchor" href="#_5-开始自由探索" aria-label="Permalink to “5. 开始自由探索！”">​</a></h2>',15)])])}const f=e(i,[["render",n]]);export{p as __pageData,f as default};
